INSERT INTO products (id, name, price_with_vat, price_without_vat, power, category, brand, image, images, badges, description, specs, features, available, documentation, youtube_url, sort_order) VALUES ('tiger-704FMD', 'TIGER 704 FMD-TB', 699000, 577686, '70 HP', 'Traktory', 'TIGER', '/images/TIGER704FMD/%201.jpg', '["/images/TIGER704FMD/%201.jpg","/images/TIGER704FMD/%202.jpg","/images/TIGER704FMD/%203.jpg","/images/TIGER704FMD/%204.jpg","/images/TIGER704FMD/%205.jpg","/images/TIGER704FMD/%206.jpg","/images/TIGER704FMD/%207.jpg","/images/TIGER704FMD/%208.jpg","/images/TIGER704FMD/%209.jpg","/images/TIGER704FMD/%2010.jpg","/images/TIGER704FMD/%2011.jpg","/images/TIGER704FMD/%2012.jpg","/images/TIGER704FMD/%2013.jpg","/images/TIGER704FMD/%2014.jpg","/images/TIGER704FMD/%2015.jpg","/images/TIGER704FMD/%2016.jpg","/images/TIGER704FMD/%2017.jpg","/images/TIGER704FMD/%2018.jpg","/images/TIGER704FMD/%2019.jpg","/images/TIGER704FMD/%2020.jpg","/images/TIGER704FMD/%2021.jpg","/images/TIGER704FMD/%2022.jpg","/images/TIGER704FMD/%2023.jpg","/images/TIGER704FMD/%2024.jpg","/images/TIGER704FMD/%2025.jpg","/images/TIGER704FMD/%2026.jpg","/images/TIGER704FMD/%2027.jpg","/images/TIGER704FMD/%2028.jpg","/images/TIGER704FMD/%2029.jpg","/images/TIGER704FMD/%2030.jpg"]'::jsonb, '["VÝKONNÝ","KLIMATIZACE","PROFESIONÁLNÍ"]'::jsonb, 'Středně výkonný traktor s luxusní kabinou, klimatizací a zadní kamerou. Zesílený rám TB – vhodný pro univerzální práci v náročnějším terénu.Traktor nelze registrovat na SPZ.', '{"Motor":"4válcový diesel, 3800 ccm, turbo","Výkon motoru":"51,5 kW / 70 HP","Typ pohonu":"2WD / 4WD","Převodovka":"12 vpřed / 12 vzad, reverzní","Provozní hmotnost":"2880 kg","Síla zdvihu 3-bodového závěsu":"1250 kg","Možnost instalace předního nakladače":"TZ06D s lopatou 4v1 s nosností 600 kg"}'::jsonb, '["Zesílený podvozek s pevnější koncovou převodovkou a optimalizovanými ozubenými koly zajišťuje vysokou spolehlivost a dlouhou životnost.","Rovná podlaha a volitelná kabina se čtyřsloupkovou konstrukcí poskytují vynikající výhled a pohodlné pracovní prostředí","Zadní vícesměrný hydraulický rozvaděč s možností nastavení tlaku usnadňuje údržbu a zvyšuje efektivitu při práci s příslušenstvím","Jednoduché mechanické ovládání, žádná elektroinika","Hlavní palivová nádrž 70 l + volitelná pomocná 50 l → celková kapacita až 120 l, což zajišťuje delší provoz bez tankování."]'::jsonb, true, '/docs/traktory/parametry_TIGER704FMD-TB.pdf', NULL, 2) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, price_with_vat = EXCLUDED.price_with_vat, price_without_vat = EXCLUDED.price_without_vat, power = EXCLUDED.power, category = EXCLUDED.category, brand = EXCLUDED.brand, image = EXCLUDED.image, images = EXCLUDED.images, badges = EXCLUDED.badges, description = EXCLUDED.description, specs = EXCLUDED.specs, features = EXCLUDED.features, available = EXCLUDED.available, documentation = EXCLUDED.documentation, youtube_url = EXCLUDED.youtube_url, sort_order = EXCLUDED.sort_order, updated_at = now();
INSERT INTO products (id, name, price_with_vat, price_without_vat, power, category, brand, image, images, badges, description, specs, features, available, documentation, youtube_url, sort_order) VALUES ('tiger-1004', 'TIGER 1004 FMD-TB', 699000, 577686, '100 HP', 'Traktory', 'TIGER', '/images/TIGER1004FMD/%201.jpg', '["/images/TIGER1004FMD/%201.jpg","/images/TIGER1004FMD/%202.jpg","/images/TIGER1004FMD/%203.jpg","/images/TIGER1004FMD/%204.jpg","/images/TIGER1004FMD/%205.jpg","/images/TIGER1004FMD/%206.jpg","/images/TIGER1004FMD/%207.jpg","/images/TIGER1004FMD/%208.jpg","/images/TIGER1004FMD/%209.jpg","/images/TIGER1004FMD/%2010.jpg","/images/TIGER1004FMD/%2011.jpg","/images/TIGER1004FMD/%2012.jpg","/images/TIGER1004FMD/%2013.jpg","/images/TIGER1004FMD/%2015.jpg","/images/TIGER1004FMD/%2017.jpg","/images/TIGER1004FMD/%2018.jpg"]'::jsonb, '["VÝKONNÝ","KLIMATIZACE","PROFESIONÁLNÍ"]'::jsonb, 'Středně výkonný traktor s luxusní kabinou, klimatizací a zadní kamerou. Zesílený rám 4WD – vhodný pro univerzální práci v náročnějším terénu. Traktor nelze registrovat na SPZ.', '{"Motor":"4válcový diesel, 3800 ccm, turbo","Výkon motoru":"74 kW / 100 HP","Typ pohonu":"2WD / 4WD","Převodovka":"12 vpřed / 12 vzad, reverzní","Provozní hmotnost":"3260 kg","Síla zdvihu 3-bodového závěsu":"1820 kg","Možnost instalace předního nakladače":"TZ06D s lopatou 4v1 s nosností 800 kg"}'::jsonb, '["Nová čtyřsloupková kabina s moderním a atraktivním vzhledem, poskytující vynikající těsnost a komfortní pracovní prostředí","Výkonný hydraulický zvedací systém umožňuje efektivní práci s připojeným nářadím a vyšší zvedací sílu.","Rozšířená palivová soustava s hlavní a pomocnou nádrží o celkové kapacitě až 190 l zajišťuje dlouhou provozní výdrž bez nutnosti častého tankování.","Převodovka s 12 rychlostmi vpřed a 12 vzad (F12 + R12), reverzační řazení a ovládání hlavní i vedlejší spojky poskytují široký rozsah rychlostí a plynulý chod při práci na poli i při přepravě.","Záruka 2 roky nebo 500 motohodin"]'::jsonb, true, '/docs/traktory/parametry_TIGER1004FMD-TB.pdf', NULL, 3) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, price_with_vat = EXCLUDED.price_with_vat, price_without_vat = EXCLUDED.price_without_vat, power = EXCLUDED.power, category = EXCLUDED.category, brand = EXCLUDED.brand, image = EXCLUDED.image, images = EXCLUDED.images, badges = EXCLUDED.badges, description = EXCLUDED.description, specs = EXCLUDED.specs, features = EXCLUDED.features, available = EXCLUDED.available, documentation = EXCLUDED.documentation, youtube_url = EXCLUDED.youtube_url, sort_order = EXCLUDED.sort_order, updated_at = now();
INSERT INTO products (id, name, price_with_vat, price_without_vat, power, category, brand, image, images, badges, description, specs, features, available, documentation, youtube_url, sort_order) VALUES ('tiger-1204', 'TIGER 1204 FMD-TD', 899000, 742975, '120 HP', 'Traktory', 'TIGER', '/images/TIGER1204FMD/%201.jpg', '["/images/TIGER1204FMD/%201.jpg","/images/TIGER1204FMD/%202.jpg","/images/TIGER1204FMD/%203.jpg","/images/TIGER1204FMD/%204.jpg","/images/TIGER1204FMD/%205.jpg","/images/TIGER1204FMD/%206.jpg","/images/TIGER1204FMD/%207.jpg","/images/TIGER1204FMD/%208.jpg","/images/TIGER1204FMD/%209.jpg","/images/TIGER1204FMD/%2010.jpg","/images/TIGER1204FMD/%2011.jpg","/images/TIGER1204FMD/%2012.jpg","/images/TIGER1204FMD/%2013.jpg","/images/TIGER1204FMD/%2015.jpg","/images/TIGER1204FMD/%2017.jpg","/images/TIGER1204FMD/%2018.jpg"]'::jsonb, '["VÝKONNÝ","KLIMATIZACE","TĚŽKÁ KATEGORIE"]'::jsonb, 'Výkonný traktor střední kategorie s luxusní kabinou a klimatizací. Těžké robustní šasi 4WD – určeno pro profesionální zemědělské nasazení. Traktor nelze registrovat na SPZ.', '{"Motor":"6válcový diesel,  6490 ccm","Výkon motoru":"88,3 kW / 120 HP","Typ pohonu":"2WD / 4WD","Převodovka":"16 vpřed / 8 vzad (24 vpřed / 8 vzad)","Řazení":"stálé záběry, posuvná objímka bez synchronů","Poznámka":"Jednoduchá a velmi odolná převodovka; vyžaduje řazení se spojkou (u zpátečky bez synchronu)","Provozní hmotnost":"4230 kg","Síla zdvihu 3-bodového závěsu":"2210 kg","Možnost instalace předního nakladače":"TZ12D s lopatou 4v1 s nosností 1200 kg"}'::jsonb, '["Podvozek TD, převodovka 16 + 8 rychlostí (volitelně 24 + 8 s plazivými stupni), zesílené poloosy, převody Haitian a klíčové části ložisek zajišťují vysokou odolnost a dlouhou životnost.","Kabina s centrálním ovládáním, velkým pracovním prostorem a komfortním sedadlem Graham poskytuje maximální komfort při řízení","Dělený a zesílený tříbodový zvedací systém, zesílené závěsy a hydraulické válce Canadian Red Lion snižují poruchovost a zvyšují spolehlivost","Hlavní nádrž 150 l + pomocná 60 l = celkem 210 l → delší pracovní výdrž bez tankování.","Přidané boční kryty motoru zvyšují celkovou pevnost a odolnost traktoru."]'::jsonb, true, '/docs/traktory/parametry_TIGER1204FMD-TD.pdf', NULL, 4) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, price_with_vat = EXCLUDED.price_with_vat, price_without_vat = EXCLUDED.price_without_vat, power = EXCLUDED.power, category = EXCLUDED.category, brand = EXCLUDED.brand, image = EXCLUDED.image, images = EXCLUDED.images, badges = EXCLUDED.badges, description = EXCLUDED.description, specs = EXCLUDED.specs, features = EXCLUDED.features, available = EXCLUDED.available, documentation = EXCLUDED.documentation, youtube_url = EXCLUDED.youtube_url, sort_order = EXCLUDED.sort_order, updated_at = now();
INSERT INTO products (id, name, price_with_vat, price_without_vat, power, category, brand, image, images, badges, description, specs, features, available, documentation, youtube_url, sort_order) VALUES ('jinma-254e', 'JINMA 254E', 289000, 238843, '25 HP', 'Traktory', 'JINMA', '/images/JINMA254E/%201.jpg', '["/images/JINMA254E/%201.jpg","/images/JINMA254E/%202.jpg","/images/JINMA254E/%203.jpg","/images/JINMA254E/%204.jpg","/images/JINMA254E/%205.jpg","/images/JINMA254E/%206.jpg","/images/JINMA254E/%207.JPG","/images/JINMA254E/%208.JPG","/images/JINMA254E/%209.JPG","/images/JINMA254E/%2010.JPG","/images/JINMA254E/%2011.JPG","/images/JINMA254E/%2012.JPG","/images/JINMA254E/%2013.JPG","/images/JINMA254E/%2014.JPG"]'::jsonb, '["KOMPAKTNÍ"]'::jsonb, 'Kompaktní 25HP traktor s možností 4×4, jednoduchá mechanika pro menší farmy a zahrady. Traktor schválený pro provoz na pozemních komunikacích – lze registrovat na SPZ', '{"Výkon motoru":"25 HP","Pohon":"2WD / 4WD","Rozměry (D×Š×V)":"3265×1440–1640×2450 mm","Rozvor":"1670 mm","Světlá výška":"320 mm","Rychlost":"až 28 km/h","Převodovka":"8 vpřed /2 vzad","Hmotnost":"1527 kg"}'::jsonb, '["Kompaktní rozměry pro malé prostory","Volitelný pohon 4WD","ROPS ochrana / kabina s topením","Nízká spotřeba paliva","Jednoduchá obsluha a údržba","Možnost instalace předního nakladače s lopatou 4v1 s nosností 450 kg"]'::jsonb, true, '/docs/traktory/parametry_JINMA254E.pdf', 'https://www.youtube.com/watch?v=syMEHg3-n-8', 5) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, price_with_vat = EXCLUDED.price_with_vat, price_without_vat = EXCLUDED.price_without_vat, power = EXCLUDED.power, category = EXCLUDED.category, brand = EXCLUDED.brand, image = EXCLUDED.image, images = EXCLUDED.images, badges = EXCLUDED.badges, description = EXCLUDED.description, specs = EXCLUDED.specs, features = EXCLUDED.features, available = EXCLUDED.available, documentation = EXCLUDED.documentation, youtube_url = EXCLUDED.youtube_url, sort_order = EXCLUDED.sort_order, updated_at = now();
INSERT INTO products (id, name, price_with_vat, price_without_vat, power, category, brand, image, images, badges, description, specs, features, available, documentation, youtube_url, sort_order) VALUES ('yto-nly954', 'YTO NLY95', 0, 0, '95 HP', 'Traktory', 'YTO', '/images/YTO_NLY/%201.jpg', '["/images/YTO_NLY/%201.jpg","/images/YTO_NLY/%202.jpg","/images/YTO_NLY/%203.jpg","/images/YTO_NLY/%204.jpg","/images/YTO_NLY/%205.jpg","/images/YTO_NLY/%206.jpg","/images/YTO_NLY/%207.jpg","/images/YTO_NLY/%208.jpg"]'::jsonb, '["KLIMATIZACE"]'::jsonb, 'Profesionální traktor z řady NLY s motorem YTO Stage V (nízké vibrace / hluk) a vysokou pracovní účinností. Traktor schválený pro provoz na pozemních komunikacích – lze registrovat na SPZ', '{"Výkon motoru":"95 HP","Motor":"YTO Stage V (nízké vibrace/hluk)","Převodovka":"12 vpřed /12 vzad, reverzní","Provozní hmotnost":"4400 kg","Síla zdvihu 3-bodového závěsu":"2500 kg","Možnost instalace předního nakladače":"TZ10D s lopatou 4v1 s nosností 1000 kg"}'::jsonb, '["Čtyřválcový dieselový motor YTO s emisní normou Euro V – silný výkon a nízká spotřeba paliva.","Převodovka 12 rychlostí vpřed + 12 rychlostí vzad, široký rozsah rychlostí, vysoká účinnost","Hydraulické kotoučové brzdy – úspora síly při brzdění, vysoká účinnost brzd, synchronizované propojení s předním náhonem při brzdění pro vyšší bezpečnost","Elektrohydraulicky ovládaný vývodový hřídel (PTO) – snadné a pohodlné ovládání jediným dotykem","Plně uzavřená čtyřsloupková kabina – široký výhled, klimatizace, topení"]'::jsonb, true, '/docs/traktory/parametry_YTO_NLY954.pdf', 'https://www.youtube.com/watch?v=BFAVBC1pHJ8', 6) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, price_with_vat = EXCLUDED.price_with_vat, price_without_vat = EXCLUDED.price_without_vat, power = EXCLUDED.power, category = EXCLUDED.category, brand = EXCLUDED.brand, image = EXCLUDED.image, images = EXCLUDED.images, badges = EXCLUDED.badges, description = EXCLUDED.description, specs = EXCLUDED.specs, features = EXCLUDED.features, available = EXCLUDED.available, documentation = EXCLUDED.documentation, youtube_url = EXCLUDED.youtube_url, sort_order = EXCLUDED.sort_order, updated_at = now();
