INSERT INTO products (id, name, price_with_vat, price_without_vat, power, category, brand, image, images, badges, description, specs, features, available, documentation, youtube_url, sort_order) VALUES ('yto-nmf554c', 'YTO NMF 554C', 549000, 453719, '55 HP', 'Traktory', 'YTO', '/images/YTO_NMF/%201.jpg', '["/images/YTO_NMF/%201.jpg","/images/YTO_NMF/%202.jpg","/images/YTO_NMF/%203.jpg","/images/YTO_NMF/%204.jpg","/images/YTO_NMF/%205.jpg","/images/YTO_NMF/%206.jpg","/images/YTO_NMF/%207.jpg","/images/YTO_NMF/%208.jpg","/images/YTO_NMF/%209.jpg"]'::jsonb, '["UNIVERZÁLNÍ"]'::jsonb, 'Kompaktní traktor z řady NMF určené pro menší a střední farmy. Univerzální použití s výborným poměrem cena/výkon. Traktor schválený pro provoz na pozemních komunikacích – lze registrovat na SPZ', '{"Výkon motoru":"55 HP","Motor":"YTO Stage V (nízké vibrace / hluk)","Převodovka":"12 vpřed /12 vzad, reverzní","Provozní hmotnost":"2770 kg","Síla zdvihu 3-bodového závěsu":"1350 kg","Možnost instalace předního nakladače":"TZ06D s lopatou 4v1 s nosností 600 kg"}'::jsonb, '["Tato řada traktorů má nový vzhled, vynikající výkon a je vhodná pro zemědělské práce, přepravu a další projektové činnosti","Vysokotlaký dieselový motor Doosan s elektronickým řízením vstřikování paliva (common rail), emisní norma stupně V, silný výkon, nízká spotřeba paliva a vysoká účinnost","12 rychlostí vpřed + 12 rychlostí vzad, rychlé přepínání mezi jízdou vpřed a vzad, vysoká efektivita","Elektrohydraulické ovládání vývodového hřídele (PTO), snadné ovládání jedním dotykem, pohodlný provoz","Mokré vícelamelové brzdy s automatickým zesílením, stabilní a spolehlivý brzdný účinek","Plně uzavřená čtyřsloupková kabina s širokým výhledem, klimatizací a topným systémem"]'::jsonb, true, '/docs/traktory/parametry_YTO_NMF554C.pdf', NULL, 9) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, price_with_vat = EXCLUDED.price_with_vat, price_without_vat = EXCLUDED.price_without_vat, power = EXCLUDED.power, category = EXCLUDED.categ