INSERT INTO manufacturers (id, name, description, youtube_video_id, sort_order) VALUES ('jinma', 'Jinma', 'Jiangsu Yueda Intelligent Agricultural Equipment Co, Ltd (dále jen Yueda Intelligent Agricultural Equipment Co, Ltd) je holdingová společnost společnosti Jiangsu Yueda Investment Co., LTD, (kód akcií 600805), The Yueda Intelligent Agricultural Equipment je hlavní společností skupiny Jiangsu Yueda Group co ., LTD. Základní kapitál je 71,5 mil. USD, zaměstnává více jak 1000 lidí, pokrývá plochu 340000 metrů čtverečních. Yueda Intelligent Agricultural Equipment má téměř sto druhů produktů. Vyrábí traktory s výkonem 16-250HP. Na domácím trhu firma JINMA pokrývá prodejem svých strojů více než 30 provincií v Číně, exportuje také do Severní Ameriky, Evropy, Jižní Ameriky, Afriky, jihovýchodní Asie a oblasti Středního východu. Jiangsu Yueda Intelligent Agricultural Equipment Co, Ltd. má nejmodernější továrnu, která má roční kapacitu 100 000 traktorů. Silná stránka firmy JINMA je v oblastit vývoje, výzkumu a systému zajišťování kvality svých traktorů. Traktor JINMA je jednou z nejoblíbenějších značek traktorů na světě. Každý traktor má svůj vlastní COC list, na základě kterého  jej lze přihlásit na SPZ.', 'syMEHg3-n-8', 0) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, youtube_video_id = EXCLUDED.youtube_video_id, sort_order = EXCLUDED.sort_order;
INSERT INTO manufacturers (id, name, description, youtube_video_id, sort_order) VALUES ('yto', 'YTO', 'Firma YTO Co., Ltd., nebo YTO, začala vyrábět zemědělské stroje již v roce 1955, zejména traktory, sklizňovou techniku, zemědělské nářadí, dieselové motory a generátory. YTO je významným a dlouholetým výrobcem zemědělských strojů v Číně. Její předchůdce, China First Tractor Company, byl jedním ze 156 hlavních projektů v prvním pětiletém plánu (1953-57) a stal se gigantem v čínském zemědělském průmyslu. V roce 1997 byla založena společnost YTO Co., Ltd.
INSERT INTO manufacturers (id, name, description, youtube_video_id, sort_order) VALUES ('samtra', 'SAMTRA', 'SAMTRA je výrobce zemědělského příslušenství, který se specializuje na širokou škálu nářadí a přídavných zařízení pro traktory a zemědělské stroje. V portfoliu nabízí radlice, plečky, sněhové frézy, mulčovače, sekačky, shrnovače, diskové brány a mnoho dalšího. Příslušenství SAMTRA je navrženo pro maximální kompatibilitu s traktory TIGER, JINMA a YTO, což zajišťuje bezproblémové nasazení a vysokou produktivitu. Všechny produkty SAMTRA jsou vyráběny s důrazem na kvalitu a odolnost, aby zvládly i ty nejnáročnější podmínky v zemědělství. Kompletní katalog příslušenství SAMTRA najdete ke stažení na stránce Příslušenství.', NULL, 2) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, youtube_video_id = EXCLUDED.youtube_video_id, sort_order = EXCLUDED.sort_order;
